1: export interface FieldSchema {
2:   name: string;
3:   required?: boolean;
4:   minLength?: number;
5:   pattern?: RegExp;
6: }
7: 
8: export interface ValidationError {
9:   field: string;
10:   message: string;
11: }
12: 
13: export function validateForm(
14:   schema: FieldSchema[],
15:   values: Record<string, string>
16: ): ValidationError[] {
17:   const errors: ValidationError[] = [];
18: 
19:   for (const field of schema) {
20:     const value = values[field.name];
21: 
22:     if (field.required && value == null) {
23:       errors.push({ field: field.name, message: `${field.name} is required` });
24:       continue;
25:     }
26: 
27:     if (field.minLength && value && value.length < field.minLength) {
28:       errors.push({
29:         field: field.name,
30:         message: `${field.name} must be at least ${field.minLength} characters`,
31:       });
32:     }
33: 
34:     if (field.pattern && value && !field.pattern.test(value)) {
35:       errors.push({ field: field.name, message: `${field.name} format is invalid` });
36:     }
37:   }
38: 
39:   return errors;
40: }
